  "content": "<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Simple Plane Game</title>
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }
  body { background: #0a0e27; display: flex; justify-content: center; align-items: center; height: 100vh; font-family: Arial, sans-serif; color: #fff; }
  #gameContainer { position: relative; }
  canvas { border: 2px solid #2a3f5f; background: linear-gradient(#0a0e27, #1a2a4a); display: block; }
  #ui { position: absolute; top: 10px; left: 10px; font-size: 18px; text-shadow: 1px 2px #000; pointer-events: none; }
  #startScreen, #gameOverScreen { position: absolute; inset: 0; background: rgba(0,0,0,0.7); display: flex; flex-direction: column; justify-content: center; align-items: center; gap: 15px; }
  .hidden { display: none !important; }
  button { padding: 12px 30px; font-size: 18px; cursor: pointer; background: #4a9eff; border: none; color: #fff; border-radius: 5px; }
  button:hover { background: #2a7eef; }
</style>
</head>
<body>
<div id="gameContainer">
  <canvas id="game" width="480" height="640"></canvas>
  <div id="ui">Score: <span id="score">0</span></div>
  <div id="startScreen">
    <h1>✈️ Plane Game</h1>
    <p>Arrow keys / WASD to move</p>
    <p>Space to shoot</p>
    <button id="startBtn">Start Game</button>
  </div>
 <div id="gameOverScreen" class="hidden">
    <h1>Game Over</h1>
   <p>Score: <span id="finalScore">0</span></p>
    <button id="restartBtn">Play Again</button>
  </div>
</div>

<script>
const canvas = document.getElementById('game');
const ctx = canvas.getContext('2d');
const W = canvas.width, H = canvas.height;

let gameState = 'start'; // start | playing | over
let score = 0;
let keys = {};
let plane, bullets, enemies, particles, stars, enemySpawnTimer, difficulty;

function init() {
  plane = { x: W/2, y: H - 80, w: 40, h: 40, speed: 5, cooldown: 0 };
  bullets = [];
  enemies = [];
  particles = [];
 stars = Array.from({length: 60}, () => ({ x: Math.random()*W, y: Math.random()*H, speed: 0.5 + Math.random()*1.5, size: Math.random()*2 }));
  score = 0;
  difficulty = 1;
  enemySpawnTimer = 0;
  document.getElementById('score').textContent = '0';
}

function spawnEnemy() {
  const size = 30 + Math.random()*20;
  enemies.push({
    x: Math.random()*(W - size),
    y: -size,
    w: size, h: size,
    speed: 1.5 + Math.random()*2 + difficulty*0.3,
    hp: 1 + Math.floor(difficulty/3)
  });
}
function createExplosion(x, y, color, count=12) {
  for (let i = 0; i < count; i++) {
    const angle = Math.random()*Math.PI*2;
    const speed = 1 + Math.random()*3;
    particles.push({
      x, y, vx: Math.cos(angle)*speed, vy: Math.sin(angle)*speed,
      life: 1, decay: 0.02 + Math.random()*0.03, color, size: 2 + Math.random()*3
    });
  }
}

function update() {
  if (gameState !== 'playing') return;

  // Plane movement
  if (keys['ArrowLeft'] || keys['KeyA']) plane.x -= plane.speed;
  if (keys['ArrowRight'] || keys['KeyD']) plane.x += plane.speed;
  if (keys['ArrowUp'] || keys['KeyW']) plane.y -= plane.speed;
  if (keys['ArrowDown'] || keys['KeyS']) plane.y += plane.speed;
  plane.x = Math.max(0, Math.min(W - plane.w, plane.x));
  plane.y = Math.max(0, Math.min(H - plane.h, plane.y));

  // Shooting
  if (plane.cooldown > 0) plane.cooldown--;
  if (keys['Space'] && plane.cooldown <= 0) {
    bullets.push({ x: plane.x + plane.w/2 - 2, y: plane.y, w: 4, h: 12, speed: 8 });
    plane.cooldown = 8;
  }

  // Bullets
  for (let i = bullets.length - 1; i >= 0; i--) {
    bullets[i].y -= bullets[i].speed;
    if (bullets[i].y + bullets[i].h < 0) bullets.splice(i, 1);
  }

  // Enemies
  enemySpawnTimer++;
  const spawnRate = Math.max(20, 60 - difficulty*3);
  if (enemySpawnTimer >= spawnRate) {
    spawnEnemy();
    enemySpawnTimer = 0;
 }
  for (let i = enemies.length - 1; i >= 0; i--) {
   enemies[i].y += enemies[i].speed;
    if (enemies[i].y > H + 50) enemies.splice(i, 1);
  }
  // Collisions: bullets vs enemies
 for (let i = bullets.length - 1; i >= 0; i--) {
    for (let j = enemies.length - 1; j >= 0; j--) {
      const b = bullets[i], e = enemies[j];
      if (!b || !e) continue;
      if (b.x < e.x+e.w && b.x+b.w > e.x && b.y < e.y+e.h && b.y+b.h > e.y) {
        e.hp--;
        bullets.splice(i, 1);
        if (e.hp <= 0) {
          createExplosion(e.x+e.w/2, e.y+e.h/2, '#ff6b35');
          score += 10;
          document.getElementById('score').textContent = score;
          enemies.splice(j, 1);
          difficulty = 1 + Math.floor(score / 50);
        }
        break;
      }
    }
  }

  // Collisions: plane vs enemies
  for (let i = enemies.length - 1; i >= 0; i--) {
    const e = enemies[i], p = plane;
   if (e.x < p.x+p.w && e.x+e.w > p.x && e.y < p.y+p.h && e.y+e.h > p.y) {
      createExplosion(p.x+p.w/2, p.y+p.h/2, '#ff444', 25);
      enemies.splice(i, 1);
      endGame();
      return;
   }
  }

  // Particles
  for (let i = particles.length - 1; i >= 0; i--) {
    const pt = particles[i];
   pt.x += pt.vx; pt.y += pt.vy;
    pt.life -= pt.decay;
    if (pt.life <= 0) particles.splice(i, 1);
  }

  // Stars
  for (const s of stars) {
    s.y += s.speed;
    if (s.y > H) { s.y = 0; s.x = Math.random()*W; }
  }
}

function draw() {
  // Background
  ctx.fillStyle = '#0a0e27';
  ctx.fillRect(0, 0, W, H);

  // Stars
  ctx.fillStyle = '#ffffff';
  for (const s of stars) {
    ctx.globalAlpha = 0.3 + s.size/2 * 0.7;
   ctx.fillRect(s.x, s.y, s.size, s.size);
  }
  ctx.globalAlpha = 1;

  if (gameState === 'start') return;

  // Plane
  ctx.save();
 ctx.translate(plane.x + plane.w/2, plane.y + plane.h/2);
  ctx.fillStyle = '#4a9eff';
  ctx.beginPath();
  ctx.moveTo(0, -plane.h/2);
  ctx.lineTo(-plane.w/2, plane.h/2);
  ctx.lineTo(plane.w/2, plane.h/2);
  ctx.closePath();
  ctx.fill();
  ctx.strokeStyle = '#8ac4ff';
  ctx.lineWidth = 2;
  ctx.stroke();
  // Cockpit
  ctx.fillStyle = '#addff';
  ctx.beginPath();
  ctx.ellipse(0, -5, 6, 10, 0, 0, Math.PI*2);
  ctx.fill();
  ctx.restore();

 // Bullets
  ctx.fillStyle = '#ffff00';
  ctx.shadowColor = '#ffff00';
 ctx.shadowBlur = 8;
  for (const b of bullets) {
    ctx.fillRect(b.x, b.y, b.w, b.h);
  }
  ctx.shadowBlur = 0;
  // Enemies
  for (const e of enemies) {
    ctx.save();
    ctx.translate(e.x + e.w/2, e.y + e.h/2);
    ctx.fillStyle = '#ff4444';
    ctx.beginPath();
    ctx.moveTo(0, e.h/2);
    ctx.lineTo(-e.w/2, -e.h/2);
    ctx.lineTo(e.w/2, -e.h/2);
    ctx.closePath();
    ctx.fill();
    ctx.strokeStyle = '#ff8888';
    ctx.lineWidth = 2;
    ctx.stroke();
   ctx.restore();
  }

  // Particles
  for (const p of particles) {
    ctx.globalAlpha = p.life;
    ctx.fillStyle = p.color;
    ctx.fillRect(p.x - p.size/2, p.y - p.size/2, p.size, p.size);
  }
  ctx.globalAlpha = 1;
}

function endGame() {
  gameState = 'over';
  document.getElementById('finalScore').textContent = score;
  document.getElementById('gameOverScreen').classList.remove('hidden');
}

function loop() {
  update();
  draw();
  requestAnimationFrame(loop);
}

document.addEventListener('keydown', e => {
  keys[e.code] = true;
 if (e.code === 'Space') e.preventDefault();
});
document.addEventListener('keyup', e => keys[e.code] = false);

document.getElementById('startBtn').addEventListener('click', () => {
  init();
  gameState = 'playing';
  document.getElementById('startScreen').classList.add('hidden');
});
document.getElementById('restartBtn').addEventListener('click', () => {
  init();
  gameState = 'playing';
  document.getElementById('gameOverScreen').classList.add('hidden');
});

init();
loop();
</script>
</body>
</html>
